function x418155_get_item_table_id( varMap , varPlayer )
	local bag_id = GetBagIndexOfUsedItem( varMap , varPlayer );
	
	if ( bag_id == nil ) then
		return nil
	end
	
	local item_id = GetItemIDByIndexInBag( varMap , varPlayer , bag_id );
	
	if ( item_id == nil ) then
		return nil
	end
	
	return item_id
end


function x418155_get_item_key( varMap , varPlayer )
	local item_id = x418155_get_item_table_id( varMap , varPlayer );
	
	if ( item_id == nil ) then
		return	nil
	end
	
	local key = x418155_item_key_array[ item_id ];
	
	if ( key == nil ) or ( key > getn( x418155_item_array ) ) then
		return nil
	end
	
	return key
end

function x418155_get_random_key( varLevel )
	if ( varLevel == 10 ) then
		return 1
	end
	
	if ( varLevel == 20 ) then
		return 2;
	end
	
	return nil
end


function x418155_ProcDoEnum( varMap, varPlayer, varTalknpc, varQuest)

	local tb_id = x418155_get_item_key( varMap , varPlayer );
	
	if ( tb_id == nil ) then
		return
	end
	
	local lv = GetLevel( varMap , varPlayer );
	
	StartTalkTask(varMap);
	TalkAppendString( varMap , "\t《成吉思汗3》专门为新手准备的礼物，当您达到相应的等级，即可获得成长礼包中的礼物。\n\t玩家在打开礼包时，需要注意自己的背包空间，已使用的礼包为灰色，未使用的礼包为黑色。" );
	
	for varI,s in x418155_item_array do
	
		local clr = nil;
