			clr = x418155_title_disabled_color;
		else
			clr = x418155_title_enabled_color;
		end
		
		TalkAppendButton( varMap , 10262 , clr.."新手成长包("..tostring( s.lv ).."级)" , 3 , varI );
	end
	
	StopTalkTask( varMap)
	DeliverTalkMenu( varMap, varPlayer, varPlayer)
end




